// Vanilla JavaScript
document.getElementById('myElement').style.display = 'none';

// jQuery - สั้นกว่ามาก!
$('#myElement').hide();

// เลือกด้วย ID
$('#myId')

// เลือกด้วย Class
$('.myClass')

// เลือกด้วย Element
$('p')

// เลือกด้วย Attribute
$('input[type="text"]')

// เลือกแบบซ้อน
$('div.container > p.highlight:first-child')

// เปลี่ยนข้อความ
$('#title').text('Hello jQuery!');

// เปลี่ยน HTML
$('#content').html('<strong>Bold Text</strong>');

// เพิ่ม Element
$('#list').append('<li>Item ใหม่</li>');
$('#list').prepend('<li>Item แรก</li>');

// ลบ Element
$('.old-item').remove();

// Clone Element
$('.template').clone().appendTo('#container');

// เปลี่ยน CSS property
$('#box').css('background-color', '#6c5ce7');

// เปลี่ยนหลาย properties
$('#box').css({
  'color': '#fff',
  'font-size': '18px',
  'border-radius': '12px'
});

// เพิ่ม/ลบ Class
$('#btn').addClass('active');
$('#btn').removeClass('active');
$('#btn').toggleClass('active');

// เช็คว่ามี Class หรือไม่
if ($('#btn').hasClass('active')) {
  console.log('Button is active!');
}

// Click Event
$('#btn').click(function() {
  alert('Clicked!');
});

// Hover Event
$('#card').hover(
  function() { $(this).addClass('hovered'); },
  function() { $(this).removeClass('hovered'); }
);

// Event Delegation (สำหรับ dynamic elements)
$(document).on('click', '.dynamic-btn', function() {
  console.log('Dynamic button clicked!');
});

// Keyboard Events
$('#input').keyup(function(e) {
  if (e.key === 'Enter') {
    console.log('Enter pressed!');
  }
});

// Show / Hide
$('#panel').show(400);
$('#panel').hide(400);
$('#panel').toggle(400);

// Fade
$('#overlay').fadeIn(500);
$('#overlay').fadeOut(500);
$('#overlay').fadeTo(500, 0.5);

// Slide
$('#menu').slideDown(300);
$('#menu').slideUp(300);
$('#menu').slideToggle(300);

// Custom Animation
$('#box').animate({
  left: '250px',
  opacity: 0.5,
  width: '200px'
}, 800);
